import { useEffect } from "react";
import "./navbar.css";

function Navbar() {
    const menuvertical = document.querySelector(".menu-vertical");

    function mostrarMVertical(){
        useEffect((e) => {
        menuvertical.style.opacity = "1"
    }
    )}



    return (
        <div className="container">
            <nav className="nav">
                <ul className="nav-list">
                    <a href="index.html"><img src="LOGO-N.png" /></a>
                    <li className="nav-item"><a href="index.html">Inicio</a></li>

                    <li className="nav-item">
                        <a href="productos.html" onMouseMove={mostrarMVertical}>Productos</a>
                        <ul className="menu-vertical">
                            <li className="item-vertical"><a href="#">Burgers&Chips</a></li>
                            <li className="item-vertical"><a href="#">Bebidas</a></li>
                            <li className="item-vertical"><a href="#">Combos</a></li>
                        </ul>
                    </li>
                    <li className="nav-item"><a href="contacto.html">Contacto</a></li>
                </ul>
            </nav>
        </div>
    );
};

export default Navbar;
